declare @q nvarchar(4000), @message nvarchar(4000), @field varchar(32), @user int, @admin bit, @unit varchar(32), @year int, @r int select @admin = @@admin, @user = @@userID, @unit = @@unit, @year = nam_bd from dmstt &AccountBalanceUploadCheck;
-- Checking &Checking;
&AccountBalanceUploadInsert; update @@table set du_co_nt00 = 0 where du_no_nt00 <> 0 update @@table set du_co00 = 0 where du_no00 <> 0
if exists(select 1 from dmstt where month(ngay_ky1) = month(ngay_dn2) and day(ngay_ky1) = day(ngay_dn2)) begin update @@table set du_no_nt1 = du_no_nt00 update @@table set du_co_nt1 = du_co_nt00 update @@table set du_no1 = du_no00 update @@table set du_co1 = du_co00 end else begin update @@table set du_co_nt1 = 0 where du_no_nt1 <> 0 update @@table set du_co1 = 0 where du_no1 <> 0 end
&Updating; where a.nam = @year
